package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.Reader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVParserTest {

    @Mock
    private Lexer lexerMock;

    private CSVParser csvParser;

    @BeforeEach
    void setUp() throws Exception {
        MockitoAnnotations.openMocks(this);
        // Use reflection to create CSVParser with mocked Lexer
        csvParser = (CSVParser) java.lang.reflect.Constructor.class
                .cast(CSVParser.class.getDeclaredConstructor(Reader.class, CSVFormat.class))
                .newInstance(null, null);
        // Inject lexerMock into csvParser
        java.lang.reflect.Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, lexerMock);
    }

    @Test
    void testIsClosed_whenLexerIsClosed_returnsTrue() {
        when(lexerMock.isClosed()).thenReturn(true);
        assertTrue(csvParser.isClosed());
        verify(lexerMock).isClosed();
    }

    @Test
    void testIsClosed_whenLexerIsNotClosed_returnsFalse() {
        when(lexerMock.isClosed()).thenReturn(false);
        assertFalse(csvParser.isClosed());
        verify(lexerMock).isClosed();
    }
}
